#include <stdio.h>
#include <stdlib.h>

long long factorial(int n) {
    long long result = 1;
    for (int i = 2; i <= n; i++) {
        result *= i;
    }
    return result;
}

long long A(int n, int k) {
    return factorial(n) / factorial(n - k);
}

void solve() {
    int n, mod;
    scanf("%d %d", &n, &mod);
    if (n == 1) {
        printf("0\n");
        return;
    }
    int z_size = 1;
    long long *z = (long long *)malloc(z_size * sizeof(long long));
    z[0] = 1;
    long long aaa = 0;
    for (int i = 2; i <= n; i++) {
        int nz_size = (i - 1) * i / 2 + 1;
        long long *nz = (long long *)calloc(nz_size, sizeof(long long));
        long long *d = (long long *)calloc(z_size + 1, sizeof(long long));
        for (int w = z_size - 1; w >= 0; w--) {
            d[w] = (d[w + 1] + z[w]) % mod;
        }
        for (int w = 0; w < nz_size; w++) {
            int L = (0 > w + 1 - i) ? 0 : w + 1 - i;
            int R = (z_size - 1 < w) ? z_size - 1 : w;
            nz[w] = (d[L] - d[R + 1]) % mod;
            if (nz[w] < 0) nz[w] += mod;
        }
        long long *e = (long long *)calloc(z_size + 2, sizeof(long long));
        long long *f = (long long *)calloc(z_size + 2, sizeof(long long));
        for (int w = 0; w < z_size + 1; w++) {
            e[w + 1] = (e[w] + d[w]) % mod;
            f[w + 1] = (f[w] - w * d[w]) % mod;
        }
        int R = z_size;
        long long bbb = 0;
        for (int jj = (0 > z_size - i) ? 0 : z_size - i; jj < z_size - 2; jj++) {
            int L = jj + 2;
            bbb = (bbb + ((e[R] - e[L]) * (i + 1 + jj) + (f[R] - f[L])) * z[jj]) % mod;
        }
        for (int jj = 0; jj < z_size - i; jj++) {
            int L = jj + 2;
            R = i + jj;
            bbb = (bbb + ((e[R + 1] - e[L]) * (i + 1 + jj) + (f[R + 1] - f[L])) * z[jj]) % mod;
        }
        aaa = (aaa + (bbb * A(n, n - i)) % mod) % mod;
        free(z);
        free(d);
        free(e);
        free(f);
        z = nz;
        z_size = nz_size;
    }
    printf("%lld\n", aaa % mod);
    free(z);
}

int main() {
    solve();
    return 0;
}
